{"id":"n9","type":"processElement","position":{"x":1015,"y":500},"data":{"label":"Approve Invoice for Payment","elementType":"userTask","laneId":"lane4"}},{"id":"n10","type":"processElement","position":{"x":1200,"y":350},"data":{"label":"Post Invoice & Schedule Payment Run","elementType":"serviceTask","laneId":"lane3"}},{"id":"n11","type":"processElement","position":{"x":1385,"y":500},"data":{"label":"Confirm Payment Disbursement & Archive Records","elementType":"userTask","laneId":"lane4"}},{"id":"n12","type":"processElement","position":{"x":1570,"y":500},"data":{"label":"3-Way Match Complete","elementType":"endEvent","laneId":"lane4"}}],"edges":[{"id":"e1","source":"n1","target":"n2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e2","source":"n2","target":"n3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e3","source":"n3","target":"n4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e4","source":"n4","target":"n5","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e5","source":"n5","target":"n9","type":"sequenceFlow","data":{"kind":"conditional","label":"Matched Within Tolerance"}},{"id":"e6","source":"n5","target":"n6","type":"sequenceFlow","data":{"kind":"conditional","label":"Discrepancy Detected"}},{"id":"e7","source":"n6","target":"n7","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e8","source":"n7","target":"n8","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e9","source":"n8","target":"n4","type":"sequenceFlow","data":{"kind":"sequence","label":"Re-submit for Match"}},{"id":"e10","source":"n9","target":"n10","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e11","source":"n10","target":"n11","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e12","source":"n11","target":"n12","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
