insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'feecbfd5-4dcc-51f2-b328-8f3d14dfc7b4', 2, 'process_group', 'Direct Procurement & Sourcing', null, null, 4, null, null, null);
insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('ea25226d-1af1-541c-ae43-45de3042ed24', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', 3, 'process', 'Sourcing Request & Early Engagement', 'WBS-driven intake that routes indirect spend to Guided Buying and direct spend to a PR or a Sourcing Request, then auto-converts an approved SR into a Direct PR.', null, 0, null, null, '{"lanes":[{"id":"l1","label":"Requestor","order":0,"systemId":null},{"id":"l2","label":"Sourcing Web App","order":1,"systemId":null},{"id":"l3","label":"Procurement System (SAP S/4HANA)","order":2,"systemId":null},{"id":"l4","label":"Manager / Buyer","order":3,"systemId":null},{"id":"l5","label":"SAP Ariba (Guided Buying)","order":4,"systemId":null}],"nodes":[{"id":"s","type":"processElement","position":{"x":90,"y":50},"data":{"label":"Sourcing need identified","elementType":"startEvent","laneId":"l1"}},{"id":"a1","type":"processElement","position":{"x":275,"y":200},"data":{"label":"Enter WBS Element","elementType":"userTask","laneId":"l2","description":"Customization · Sourcing web app, refreshed daily with the WBS extract from S/4.","responsibleRole":"Requestor"}},{"id":"a2","type":"processElement","position":{"x":460,"y":200},"data":{"label":"Submit Request (Next)","elementType":"userTask","laneId":"l2","description":"Customization · Web app posts the request to S/4.","responsibleRole":"Requestor"}},{"id":"g1","type":"processElement","position":{"x":645,"y":350},"data":{"label":"Direct or Indirect WBS?","elementType":"exclusiveGateway","laneId":"l3","description":"S/4HANA · System derives Direct vs Indirect from the WBS."}},{"id":"a3","type":"processElement","position":{"x":830,"y":650},"data":{"label":"Open Guided Buying","elementType":"userTask","laneId":"l5","description":"Ariba · Indirect spend routed to Guided Buying via SSO.","responsibleRole":"Requestor"}},{"id":"e1","type":"processElement","position":{"x":1015,"y":650},"data":{"label":"Indirect handled in Guided Buying","elementType":"endEvent","laneId":"l5"}},{"id":"g2","type":"processElement","position":{"x":1200,"y":350},"data":{"label":"PR or Sourcing Request?","elementType":"exclusiveGateway","laneId":"l3","description":"S/4HANA · For Direct spend the requestor chooses a PR or an SR."}},{"id":"a4","type":"processElement","position":{"x":1385,"y":350},"data":{"label":"Create Direct PR","elementType":"userTask","laneId":"l3","description":"Customization · SSO to the S/4 Create PR app with the Direct PR document type and the WBS in account assignment.","responsibleRole":"Requestor"}},{"id":"e2","type":"processElement","position":{"x":1570,"y":350},"data":{"label":"Hand off to Direct Procurement","elementType":"endEvent","laneId":"l3"}},{"id":"a5","type":"processElement","position":{"x":1755,"y":50},"data":{"label":"Create Sourcing Request","elementType":"userTask","laneId":"l1","description":"Customization · SSO to the S/4 Create PR app with the Sourcing Request document type.","responsibleRole":"Requestor"}},{"id":"a6","type":"processElement","position":{"x":1940,"y":50},"data":{"label":"Enter SR Detail & Attachments","elementType":"userTask","laneId":"l1","description":"S/4HANA · Add the data needed to create the SR, including attachments.","responsibleRole":"Requestor"}},{"id":"a7","type":"processElement","position":{"x":2125,"y":350},"data":{"label":"Save Sourcing Request","elementType":"serviceTask","laneId":"l3","description":"S/4HANA · SR saved against the WBS."}},{"id":"g3","type":"processElement","position":{"x":2310,"y":500},"data":{"label":"Supplier exists?","elementType":"exclusiveGateway","laneId":"l4","responsibleRole":"Buyer"}},{"id":"a8","type":"processElement","position":{"x":2495,"y":500},"data":{"label":"Onboard Supplier","elementType":"userTask","laneId":"l4","description":"Outside S/4 / Ariba · Supplier onboarding for a new source.","responsibleRole":"Buyer"}},{"id":"a9","type":"processElement","position":{"x":2680,"y":500},"data":{"label":"Update Contract","elementType":"userTask","laneId":"l4","description":"Ariba · Edit the supplier contract for an existing source.","responsibleRole":"Buyer"}},{"id":"a10","type":"processElement","position":{"x":2865,"y":500},"data":{"label":"Run Sourcing Event / RFQ (optional)","elementType":"userTask","laneId":"l4","description":"Ariba · Optional sourcing event when an RFQ is required.","responsibleRole":"Buyer"}},{"id":"g4","type":"processElement","position":{"x":3050,"y":500},"data":{"label":"SR approved?","elementType":"exclusiveGateway","laneId":"l4","description":"S/4HANA · Manager verifies the buyer code, then buyer and requestor iterate until both agree and the buyer gives final approval.","responsibleRole":"Buyer"}},{"id":"a11","type":"processElement","position":{"x":3235,"y":50},"data":{"label":"Mark SR Closed","elementType":"manualTask","laneId":"l1","description":"S/4HANA · If the SR will not produce a Direct PR, close it so the auto-convert job skips it.","responsibleRole":"Requestor"}},{"id":"e3","type":"processElement","position":{"x":3420,"y":50},"data":{"label":"SR closed","elementType":"endEvent","laneId":"l1"}},{"id":"a12","type":"processElement","position":{"x":3605,"y":350},"data":{"label":"Auto-Convert SR to Direct PR","elementType":"serviceTask","laneId":"l3","description":"Customization · Scheduled job converts an approved SR into a Direct PR."}},{"id":"e4","type":"processElement","position":{"x":3790,"y":350},"data":{"label":"Direct PR created","elementType":"endEvent","laneId":"l3"}}],"edges":[{"id":"e0","source":"s","target":"a1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e1","source":"a1","target":"a2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e2","source":"a2","target":"g1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e3","source":"g1","target":"a3","type":"sequenceFlow","data":{"kind":"conditional","label":"Indirect"}},{"id":"e4","source":"a3","target":"e1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e5","source":"g1","target":"g2","type":"sequenceFlow","data":{"kind":"conditional","label":"Direct"}},{"id":"e6","source":"g2","target":"a4","type":"sequenceFlow","data":{"kind":"conditional","label":"PR"}},{"id":"e7","source":"a4","target":"e2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e8","source":"g2","target":"a5","type":"sequenceFlow","data":{"kind":"conditional","label":"Sourcing Request"}},{"id":"e9","source":"a5","target":"a6","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e10","source":"a6","target":"a7","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e11","source":"a7","target":"g3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e12","source":"g3","target":"a8","type":"sequenceFlow","data":{"kind":"conditional","label":"No - new supplier"}},{"id":"e13","source":"g3","target":"a9","type":"sequenceFlow","data":{"kind":"conditional","label":"Yes - existing"}},{"id":"e14","source":"a8","target":"a10","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e15","source":"a9","target":"a10","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e16","source":"a10","target":"g4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e17","source":"g4","target":"a12","type":"sequenceFlow","data":{"kind":"conditional","label":"Approved"}},{"id":"e18","source":"a12","target":"e4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e19","source":"g4","target":"a11","type":"sequenceFlow","data":{"kind":"conditional","label":"Rejected"}},{"id":"e20","source":"a11","target":"e3","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('a13d7f8b-c666-5c71-bbd9-5a2adf7b8bff', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', 3, 'process', 'PR Release Procedure', 'Conditional, DOA-driven PR release workflow with independent approver nodes, comment/edit loop, supply-chain buyer assignment, and nightly PR-to-PO auto-conversion.', null, 1, null, null, '{"lanes":[{"id":"l1","label":"Requestor","order":0,"systemId":null},{"id":"l2","label":"PR Release Workflow","order":1,"systemId":null},{"id":"l3","label":"Conditional Approvers","order":2,"systemId":null},{"id":"l4","label":"Supply Chain","order":3,"systemId":null},{"id":"l5","label":"Procurement System (SAP S/4HANA)","order":4,"systemId":null}],"nodes":[{"id":"s","type":"processElement","position":{"x":90,"y":50},"data":{"label":"PR released into workflow","elementType":"startEvent","laneId":"l1"}},{"id":"a1","type":"processElement","position":{"x":275,"y":50},"data":{"label":"Add Watcher (optional)","elementType":"userTask","laneId":"l1","description":"Customization · The Watcher is notified after each node is approved or rejected.","responsibleRole":"Requestor"}},{"id":"a2","type":"processElement","position":{"x":460,"y":200},"data":{"label":"Assemble Approval Workflow","elementType":"serviceTask","laneId":"l2","description":"Customization · Each approver node is added only if its predefined conditions are met; nodes are independent. A split account assignment adds the WBS owner for each WBS."}},{"id":"a3","type":"processElement","position":{"x":645,"y":350},"data":{"label":"Approver Business Review","elementType":"userTask","laneId":"l3","description":"S/4HANA · Each conditionally-added approver reviews. The Contract Administrator adds a Contract Review and the Quality Manager adds a Quality Review.","responsibleRole":"Conditional Approver (WBS Owner, Finance, Program Finance, PM, Business Development, CFO, Contracts, Quality)"}},{"id":"g1","type":"processElement","position":{"x":830,"y":350},"data":{"label":"Approved within DOA?","elementType":"exclusiveGateway","laneId":"l3","description":"S/4HANA · Delegation of Authority is checked; if the approver cannot approve the full amount, the next DOA level is added to the workflow."}},{"id":"a4","type":"processElement","position":{"x":1015,"y":350},"data":{"label":"Provide Comments","elementType":"userTask","laneId":"l3","description":"S/4HANA · Rejection returns the PR for rework.","responsibleRole":"Conditional Approver"}},{"id":"a5","type":"processElement","position":{"x":1200,"y":650},"data":{"label":"S/4 PR Creation / Edit","elementType":"serviceTask","laneId":"l5","description":"S/4HANA · PR updated per feedback, then re-enters the workflow."}},{"id":"g2","type":"processElement","position":{"x":1385,"y":200},"data":{"label":"More approver nodes?","elementType":"exclusiveGateway","laneId":"l2","description":"Customization · Loop until every conditionally-added node has approved."}},{"id":"a6","type":"processElement","position":{"x":1570,"y":500},"data":{"label":"Review Purchase Request","elementType":"userTask","laneId":"l4","description":"S/4HANA · Strategic buyer reviews the released PR.","responsibleRole":"Supply Chain Strategic Buyer"}},{"id":"g3","type":"processElement","position":{"x":1755,"y":500},"data":{"label":"Sourcing event needed?","elementType":"exclusiveGateway","laneId":"l4","description":"S/4HANA · Decide whether a sourcing event is required."}},{"id":"e2","type":"processElement","position":{"x":1940,"y":500},"data":{"label":"Sourcing event / project planning","elementType":"endEvent","laneId":"l4","description":"Ariba · Hand off to a sourcing event."}},{"id":"a7","type":"processElement","position":{"x":2125,"y":500},"data":{"label":"Assign Buyer & Verify Supplier","elementType":"userTask","laneId":"l4","description":"S/4HANA · Supply Chain Manager assigns the buyer and verifies the supplier.","responsibleRole":"Supply Chain Manager"}},{"id":"a8","type":"processElement","position":{"x":2310,"y":650},"data":{"label":"Auto-Convert PR to PO","elementType":"serviceTask","laneId":"l5","description":"Customization · Nightly job: if the PR is released, a contract exists, the total is under the auto-convert threshold, and master data is present, it converts to a PO; otherwise it is converted manually."}},{"id":"e1","type":"processElement","position":{"x":2495,"y":650},"data":{"label":"PR released for PO conversion","elementType":"endEvent","laneId":"l5"}}],"edges":[{"id":"e0","source":"s","target":"a1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e1","source":"a1","target":"a2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e2","source":"a2","target":"a3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e3","source":"a3","target":"g1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e4","source":"g1","target":"a4","type":"sequenceFlow","data":{"kind":"conditional","label":"Rejected"}},{"id":"e5","source":"a4","target":"a5","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e6","source":"a5","target":"a3","type":"sequenceFlow","data":{"kind":"sequence","label":"Resubmit"}},{"id":"e7","source":"g1","target":"g2","type":"sequenceFlow","data":{"kind":"conditional","label":"Approved"}},{"id":"e8","source":"g2","target":"a3","type":"sequenceFlow","data":{"kind":"conditional","label":"Yes - next node"}},{"id":"e9","source":"g2","target":"a6","type":"sequenceFlow","data":{"kind":"conditional","label":"No - all approved"}},{"id":"e10","source":"a6","target":"g3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e11","source":"g3","target":"e2","type":"sequenceFlow","data":{"kind":"conditional","label":"Yes"}},{"id":"e12","source":"g3","target":"a7","type":"sequenceFlow","data":{"kind":"conditional","label":"No"}},{"id":"e13","source":"a7","target":"a8","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e14","source":"a8","target":"e1","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('4a3dc3d4-61ef-5561-b1f1-2064f3fe23c0', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', 3, 'process', 'Direct Procurement Execution', 'End-to-end direct buy: PR with clause flowdowns, optional RFQ and supplier collaboration, PR-to-PO conversion with a price-change threshold gate, clause/attachment handling, and PO copy to Ariba.', null, 2, null, null, '{"lanes":[{"id":"l1","label":"Requestor","order":0,"systemId":null},{"id":"l2","label":"Supply Chain Buyer","order":1,"systemId":null},{"id":"l3","label":"Procurement System (SAP S/4HANA)","order":2,"systemId":null},{"id":"l4","label":"SAP Ariba","order":3,"systemId":null},{"id":"l5","label":"Suppliers","order":4,"systemId":null},{"id":"l6","label":"Intake & Integration","order":5,"systemId":null}],"nodes":[{"id":"s","type":"processElement","position":{"x":90,"y":800},"data":{"label":"PR request (ITSM intake)","elementType":"startEvent","laneId":"l6","description":"Outside S/4 / Ariba · Service-management tool raises the request via API."}},{"id":"a1","type":"processElement","position":{"x":275,"y":50},"data":{"label":"Create PR","elementType":"userTask","laneId":"l1","description":"S/4HANA · Assign desired vendor (optional), buyer code, WBS element, and the correct price.","responsibleRole":"Requestor"}},{"id":"a2","type":"processElement","position":{"x":460,"y":50},"data":{"label":"Validate Contract Flowdowns","elementType":"userTask","laneId":"l1","description":"Customization · Clause rules auto-populate onto the PR from the clause catalogue (Dassian Clause Library).","responsibleRole":"Requestor"}},{"id":"a3","type":"processElement","position":{"x":645,"y":50},"data":{"label":"Add / Edit Attachments","elementType":"userTask","laneId":"l1","description":"S/4HANA · Attach supporting documents.","responsibleRole":"Requestor"}},{"id":"a4","type":"processElement","position":{"x":830,"y":350},"data":{"label":"Save PR","elementType":"serviceTask","laneId":"l3","description":"S/4HANA."}},{"id":"a5","type":"processElement","position":{"x":1015,"y":350},"data":{"label":"Release PR","elementType":"userTask","laneId":"l3","description":"Customization · Handled by the PR Release Procedure flow.","responsibleRole":"PR Release Workflow"}},{"id":"a6","type":"processElement","position":{"x":1200,"y":800},"data":{"label":"Sync to eBinder","elementType":"serviceTask","laneId":"l6","description":"Outside S/4 / Ariba · Integration calls S/4 and updates the external eBinder (system of record); a scheduled job keeps it in sync."}},{"id":"g1","type":"processElement","position":{"x":1385,"y":200},"data":{"label":"RFQ needed?","elementType":"exclusiveGateway","laneId":"l2","description":"S/4HANA · Buyer decides whether to run an RFQ or convert directly."}},{"id":"a7","type":"processElement","position":{"x":1570,"y":200},"data":{"label":"Create RFQs","elementType":"userTask","laneId":"l2","description":"S/4HANA · RFQ output can be emailed or saved as PDF to send to suppliers.","responsibleRole":"Supply Chain Buyer"}},{"id":"a8","type":"processElement","position":{"x":1755,"y":200},"data":{"label":"Send RFQ to Suppliers","elementType":"userTask","laneId":"l2","description":"S/4HANA.","responsibleRole":"Supply Chain Buyer"}},{"id":"a9","type":"processElement","position":{"x":1940,"y":650},"data":{"label":"Receive RFQ & Respond","elementType":"userTask","laneId":"l5","description":"Outside S/4 / Ariba · Supplier collaboration is manual (calls, email).","responsibleRole":"Supplier"}},{"id":"a10","type":"processElement","position":{"x":2125,"y":200},"data":{"label":"Enter & Analyze Responses","elementType":"userTask","laneId":"l2","description":"S/4HANA · Responses entered into S/4 and analyzed against business must-haves.","responsibleRole":"Supply Chain Buyer"}},{"id":"a11","type":"processElement","position":{"x":2310,"y":200},"data":{"label":"Select Winning RFQ","elementType":"userTask","laneId":"l2","description":"S/4HANA.","responsibleRole":"Supply Chain Buyer"}},{"id":"a12","type":"processElement","position":{"x":2495,"y":200},"data":{"label":"Convert PR to PO","elementType":"userTask","laneId":"l2","description":"S/4HANA · Convert from the released Direct PR (or from the winning RFQ / SR).","responsibleRole":"Supply Chain Buyer"}},{"id":"g2","type":"processElement","position":{"x":2680,"y":200},"data":{"label":"Price change vs PR?","elementType":"exclusiveGateway","laneId":"l2","description":"S/4HANA · Compare the total PO price to the PR (total, not line item)."}},{"id":"g3","type":"processElement","position":{"x":2865,"y":200},"data":{"label":"Difference over threshold?","elementType":"exclusiveGateway","laneId":"l2","description":"S/4HANA · Threshold check (for example, $5K)."}},{"id":"a13","type":"processElement","position":{"x":3050,"y":200},"data":{"label":"Delete PO / Do Not Save PR","elementType":"manualTask","laneId":"l2","description":"S/4HANA · Over threshold: cancel and correct the PR before reconverting.","responsibleRole":"Supply Chain Buyer"}},{"id":"a14","type":"processElement","position":{"x":3235,"y":50},"data":{"label":"Update PR","elementType":"userTask","laneId":"l1","description":"S/4HANA · Correct the PR, then reconvert.","responsibleRole":"Requestor"}},{"id":"a15","type":"processElement","position":{"x":3420,"y":200},"data":{"label":"Modify PO / Finish Conversion","elementType":"userTask","laneId":"l2","description":"S/4HANA.","responsibleRole":"Supply Chain Buyer"}},{"id":"a16","type":"processElement","position":{"x":3605,"y":200},"data":{"label":"Add Clauses & Attachments","elementType":"userTask","laneId":"l2","description":"Customization · Clauses stored in the clause library (Dassian).","responsibleRole":"Supply Chain Buyer"}},{"id":"a17","type":"processElement","position":{"x":3790,"y":350},"data":{"label":"Save PO","elementType":"serviceTask","laneId":"l3","description":"S/4HANA."}},{"id":"a18","type":"processElement","position":{"x":3975,"y":350},"data":{"label":"Release PO & Output","elementType":"serviceTask","laneId":"l3","description":"S/4HANA · PO output issued."}},{"id":"a19","type":"processElement","position":{"x":4160,"y":500},"data":{"label":"Copy PO to Ariba","elementType":"serviceTask","laneId":"l4","description":"Ariba · PO copied to Ariba and made available to suppliers via the Supplier Network (reference and invoicing only)."}},{"id":"a20","type":"processElement","position":{"x":4345,"y":800},"data":{"label":"PO Status Update","elementType":"serviceTask","laneId":"l6","description":"Outside S/4 / Ariba · PO status returned to the service-management tool / eBinder."}},{"id":"e1","type":"processElement","position":{"x":4530,"y":500},"data":{"label":"PO issued","elementType":"endEvent","laneId":"l4","description":"Ariba · Supplier invoices against the PO."}}],"edges":[{"id":"e0","source":"s","target":"a1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e1","source":"a1","target":"a2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e2","source":"a2","target":"a3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e3","source":"a3","target":"a4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e4","source":"a4","target":"a5","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e5","source":"a5","target":"a6","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e6","source":"a6","target":"g1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e7","source":"g1","target":"a7","type":"sequenceFlow","data":{"kind":"conditional","label":"RFQ"}},{"id":"e8","source":"a7","target":"a8","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e9","source":"a8","target":"a9","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e10","source":"a9","target":"a10","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e11","source":"a10","target":"a11","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e12","source":"a11","target":"a12","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e13","source":"g1","target":"a12","type":"sequenceFlow","data":{"kind":"conditional","label":"Direct convert"}},{"id":"e14","source":"a12","target":"g2","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e15","source":"g2","target":"a15","type":"sequenceFlow","data":{"kind":"conditional","label":"No change"}},{"id":"e16","source":"g2","target":"g3","type":"sequenceFlow","data":{"kind":"conditional","label":"Price changed"}},{"id":"e17","source":"g3","target":"a15","type":"sequenceFlow","data":{"kind":"conditional","label":"Under threshold"}},{"id":"e18","source":"g3","target":"a13","type":"sequenceFlow","data":{"kind":"conditional","label":"Over threshold"}},{"id":"e19","source":"a13","target":"a14","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e20","source":"a14","target":"a1","type":"sequenceFlow","data":{"kind":"sequence","label":"Reconvert after correction"}},{"id":"e21","source":"a15","target":"a16","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e22","source":"a16","target":"a17","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e23","source":"a17","target":"a18","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e24","source":"a18","target":"a19","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e25","source":"a19","target":"a20","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e26","source":"a20","target":"e1","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('1da9d413-2932-5b2e-9c0b-70123133a972', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', 3, 'process', 'Supplier Contract Management', 'Supplier contract lifecycle: draft or amend, negotiate, execute with digital signoff, finalize and publish, one-step release that enables direct procurement, and closeout.', null, 3, null, null, '{"lanes":[{"id":"l1","label":"Buyer / Manager","order":0,"systemId":null},{"id":"l2","label":"Supplier","order":1,"systemId":null},{"id":"l3","label":"Contract System (SAP S/4HANA / Dassian)","order":2,"systemId":null}],"nodes":[{"id":"s","type":"processElement","position":{"x":90,"y":50},"data":{"label":"Contract need","elementType":"startEvent","laneId":"l1","description":"S/4HANA · Triggered by a sourcing request or a direct PR."}},{"id":"g1","type":"processElement","position":{"x":275,"y":50},"data":{"label":"Amend existing contract?","elementType":"exclusiveGateway","laneId":"l1","responsibleRole":"Buyer / Manager"}},{"id":"a1","type":"processElement","position":{"x":460,"y":50},"data":{"label":"Amend Supplier Contract","elementType":"userTask","laneId":"l1","description":"S/4HANA · Driven by an SR or Direct PR. If the contract was updated due to a Direct PR, close that Direct PR.","responsibleRole":"Buyer / Manager"}},{"id":"a2","type":"processElement","position":{"x":645,"y":50},"data":{"label":"Create Contract Draft","elementType":"userTask","laneId":"l1","description":"S/4HANA · Driven by an SR or Direct PR. If the contract was created due to a Direct PR, close that Direct PR.","responsibleRole":"Buyer / Manager"}},{"id":"a3","type":"processElement","position":{"x":830,"y":50},"data":{"label":"Negotiate & Approve Contract","elementType":"userTask","laneId":"l1","description":"Outside S/4 / Ariba · Negotiation happens outside the system (calls, email).","responsibleRole":"Buyer / Manager"}},{"id":"a4","type":"processElement","position":{"x":1015,"y":50},"data":{"label":"Execute Supplier Contract","elementType":"userTask","laneId":"l1","description":"S/4HANA.","responsibleRole":"Buyer / Manager"}},{"id":"a5","type":"processElement","position":{"x":1200,"y":200},"data":{"label":"Digital Signoff","elementType":"userTask","laneId":"l2","description":"Outside S/4 / Ariba · Supplier signs; e-signature is a nice-to-have, not required.","responsibleRole":"Supplier"}},{"id":"a6","type":"processElement","position":{"x":1385,"y":50},"data":{"label":"Finalize & Publish Contract","elementType":"userTask","laneId":"l1","description":"S/4HANA.","responsibleRole":"Buyer / Manager"}},{"id":"a7","type":"processElement","position":{"x":1570,"y":350},"data":{"label":"Release Contract","elementType":"serviceTask","laneId":"l3","description":"S/4HANA · Simple one-step release on contracts."}},{"id":"e2","type":"processElement","position":{"x":1755,"y":50},"data":{"label":"Perform Direct Procurement","elementType":"endEvent","laneId":"l1","description":"S/4HANA · Released contract enables direct procurement against it."}},{"id":"a8","type":"processElement","position":{"x":1940,"y":50},"data":{"label":"Closeout Supplier Contract","elementType":"userTask","laneId":"l1","description":"S/4HANA.","responsibleRole":"Buyer / Manager"}},{"id":"e1","type":"processElement","position":{"x":2125,"y":350},"data":{"label":"Contract closed","elementType":"endEvent","laneId":"l3"}}],"edges":[{"id":"e0","source":"s","target":"g1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e1","source":"g1","target":"a1","type":"sequenceFlow","data":{"kind":"conditional","label":"Yes - amend"}},{"id":"e2","source":"a1","target":"a3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e3","source":"g1","target":"a2","type":"sequenceFlow","data":{"kind":"conditional","label":"No - new"}},{"id":"e4","source":"a2","target":"a3","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e5","source":"a3","target":"a4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e6","source":"a4","target":"a5","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e7","source":"a5","target":"a6","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e8","source":"a6","target":"a7","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e9","source":"a7","target":"e2","type":"sequenceFlow","data":{"kind":"sequence","label":"Enables"}},{"id":"e10","source":"a7","target":"a8","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e11","source":"a8","target":"e1","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
insert into process_reference_scenarios (id, library_id, parent_id, level, node_kind, name, description, scope_item_ref, sort_order, lifecycle, variant_label, graph_data) values ('e974c78e-fed8-517f-8877-8165023c3abc', '2b514eba-f4ff-59cd-ba4c-b6c259e96b30', 'f4fb8b2a-d5fa-5ede-bc31-a50492d83d53', 3, 'process', 'Invoice Processing & Exception Handling', 'Automated PO/GR/invoice match with manual reconciliation, S/4 PO-edit exception loop that syncs back to Ariba, and accept/reject to payment.', null, 4, null, null, '{"lanes":[{"id":"l1","label":"AP Function","order":0,"systemId":null},{"id":"l2","label":"Buyer","order":1,"systemId":null},{"id":"l3","label":"SAP Ariba","order":2,"systemId":null},{"id":"l4","label":"Procurement System (SAP S/4HANA)","order":3,"systemId":null}],"nodes":[{"id":"s","type":"processElement","position":{"x":90,"y":350},"data":{"label":"Supplier invoice received","elementType":"startEvent","laneId":"l3","description":"Ariba · Invoice arrives against the PO on the Supplier Network."}},{"id":"a1","type":"processElement","position":{"x":275,"y":350},"data":{"label":"Invoice Match & Evaluation","elementType":"serviceTask","laneId":"l3","description":"Ariba · Automated match against the PO and goods receipt."}},{"id":"g1","type":"processElement","position":{"x":460,"y":50},"data":{"label":"Match result?","elementType":"exclusiveGateway","laneId":"l1","responsibleRole":"AP Function"}},{"id":"a2","type":"processElement","position":{"x":645,"y":50},"data":{"label":"Manual Reconciliation","elementType":"manualTask","laneId":"l1","description":"Ariba · Needs review; any PO change must be made in S/4.","responsibleRole":"AP Function"}},{"id":"a3","type":"processElement","position":{"x":830,"y":200},"data":{"label":"Edit PO in S/4","elementType":"userTask","laneId":"l2","description":"S/4HANA · Exception processing: buyer edits the PO.","responsibleRole":"Buyer"}},{"id":"a4","type":"processElement","position":{"x":1015,"y":200},"data":{"label":"Wait for Changes to Sync to Ariba","elementType":"serviceTask","laneId":"l2","description":"Ariba · Updated PO flows back to Ariba; reconciliation resumes.","responsibleRole":"Buyer"}},{"id":"g2","type":"processElement","position":{"x":1200,"y":50},"data":{"label":"Reconciliation outcome?","elementType":"exclusiveGateway","laneId":"l1","responsibleRole":"AP Function"}},{"id":"a5","type":"processElement","position":{"x":1385,"y":50},"data":{"label":"Send Invoice for Payment","elementType":"serviceTask","laneId":"l1","description":"S/4HANA · Accepted invoice released to payment.","responsibleRole":"AP Function"}},{"id":"a6","type":"processElement","position":{"x":1570,"y":50},"data":{"label":"Reject Invoice","elementType":"manualTask","laneId":"l1","description":"Ariba · Invoice rejected back to the supplier.","responsibleRole":"AP Function"}},{"id":"e1","type":"processElement","position":{"x":1755,"y":500},"data":{"label":"Invoice paid","elementType":"endEvent","laneId":"l4","description":"S/4HANA."}},{"id":"e2","type":"processElement","position":{"x":1940,"y":350},"data":{"label":"Invoice rejected","elementType":"endEvent","laneId":"l3"}}],"edges":[{"id":"e0","source":"s","target":"a1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e1","source":"a1","target":"g1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e2","source":"g1","target":"a5","type":"sequenceFlow","data":{"kind":"conditional","label":"Matched"}},{"id":"e3","source":"g1","target":"a2","type":"sequenceFlow","data":{"kind":"conditional","label":"Needs review"}},{"id":"e4","source":"g1","target":"a6","type":"sequenceFlow","data":{"kind":"conditional","label":"Invalid"}},{"id":"e5","source":"a2","target":"a3","type":"sequenceFlow","data":{"kind":"conditional","label":"PO correction needed"}},{"id":"e6","source":"a3","target":"a4","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e7","source":"a4","target":"a2","type":"sequenceFlow","data":{"kind":"sequence","label":"Resume reconciliation"}},{"id":"e8","source":"a2","target":"g2","type":"sequenceFlow","data":{"kind":"conditional","label":"Reconciled"}},{"id":"e9","source":"g2","target":"a5","type":"sequenceFlow","data":{"kind":"conditional","label":"Accepted"}},{"id":"e10","source":"g2","target":"a6","type":"sequenceFlow","data":{"kind":"conditional","label":"Rejected"}},{"id":"e11","source":"a5","target":"e1","type":"sequenceFlow","data":{"kind":"sequence"}},{"id":"e12","source":"a6","target":"e2","type":"sequenceFlow","data":{"kind":"sequence"}}]}'::jsonb);
